var e=[{id:`L2_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`침식체들이 폭발 반경 안으로 들어왔습니다! 어쩌죠?`,JPN:`侵食体が爆発の半径内に進入しました！　どうしましょう？`,ENG:`The C.O.s are within the blast radius, sir! What do we do?`,TWN:`侵蝕體已經進入爆炸半徑內！怎麼辦？`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`기다려! 아직 대장님이 벗어나지 못했다!`,JPN:`待て！　まだ隊長が出ていねえ！`,ENG:`Hold! The Captain's still there!`,TWN:`先等一下！隊長還沒出來！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`와트. 난 신경 쓰지 말고 기폭장치를 눌러.`,JPN:`ワット。私のことは気にせずに起爆装置を押して。`,ENG:`Watt, don't mind me. Press the ignition switch.`,TWN:`華特，別管我，按下引爆裝置。`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`예? 하지만!`,JPN:`は？　ですが！`,ENG:`What? But...!`,TWN:`什麼？可是！`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SURPRISE`}}}},{id:`L9_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`놈들이 외성을 넘으면 모두가 위험해진다! 어서!`,JPN:`やつらが外郭を越えるとみんなが危なくなる！　早く！`,ENG:`Everyone will be in danger if they break through the castle wall! Do it now!`,TWN:`敵人越過外城的話大家都會有危險！快！`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SURPRISE`}}}},{id:`L10_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`아, 알겠습니다!`,JPN:`わ、わかりました！`,ENG:`Y-yes, ma'am!`,TWN:`是…遵命！`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`하이랜더 타입……. 격퇴 확인.`,JPN:`ハイランダータイプ……撃退を確認。`,ENG:`Highlander-Type... Kill confirmed.`,TWN:`高地闊步者類型……確認擊退。`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`대장님의 모습은 확인되지 않습니다.`,JPN:`隊長の姿は確認できませんでした。`,ENG:`No signs of Captain, sir.`,TWN:`無法確認隊長情況。`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_HATE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`다들 예를 갖춰라!`,JPN:`みんな、礼をつくせ！`,ENG:`Men, atten-hut!`,TWN:`所有人行禮！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SERIOUS`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`엘라 대장님의 명예로운 희생을 기리며…… 경례!`,JPN:`エラ隊長の名誉ある犠牲を称え……敬礼！`,ENG:`Captain Ella has sacrificed her life for the greater good... Present, arms!`,TWN:`紀念艾拉隊長的光榮犧牲……敬禮！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:null,text:{KOREA:`엣취…!`,JPN:`くしゅん……！`,ENG:`Ah-choo!`,TWN:`哈啾…！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`PITER_BORDER_NULL_NAMED`,text:{KOREA:`……재채기?`,JPN:`……くしゃみ？`,ENG:`A sneeze...?`,TWN:`……噴嚏聲？`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PITER_BORDER_NULL_NAMED`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`훌쩍…`,JPN:`スンッ……`,ENG:`*Sniffle*`,TWN:`噢嗚…`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`대장님이다!`,JPN:`隊長だ！`,ENG:`It’s the Captain!`,TWN:`是隊長！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`대장님이 살아 계신다!`,JPN:`隊長が生きている！`,ENG:`She's alive!`,TWN:`隊長還活著！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};